<template>
    <div id="view-employee">
        <ul class="collection with-header">
            <li class="collection-header"><h4>{{name}}</h4></li>
            <li class="collection-item">Employee ID#: {{employee_id}}</li>
            <li class="collection-item">Department: {{dept}}</li>
            <li class="collection-item">Position : {{position}}</li>
            
        </ul>
        <router-link to="/" class="btn grey">Back</router-link>
        <button @click="deleteEmployee" class="btn red">Delete</button>
        <div class="fixed-action-btn">
            <router-link :to="{name:'editEmployee',params:{employee_id:employee_id}}" class="btn-floating btn-large red">
                <i class="fa fa-pencil"></i>
            </router-link>
        </div>
    </div>
</template>

<script>
import db from './firebaseinit'
export default {
    name: 'view-employee',
    data (){
        return{
            employee_id:null,
            dept:null,
            name:null,
            position:null
            
        }
    },
    beforeRouteEnter(to,from,next){
        db.collection('employees').where('employee_id','==',to.params.employee_id).get()
        .then((querySnapshot) =>{
            console.log(querySnapshot)
            querySnapshot.forEach((doc) => {
                next(vm => {
                    vm.employee_id=doc.data().employee_id
                    vm.dept=doc.data().dept
                    vm.name=doc.data().name
                    vm.position=doc.data().position
                })
            })
        })
    },
    watch :{
        '$route': 'fetchData'
    },
    methods:{
        fetchData(){
            db.collection('employees').where('employee_id','==',this.$route.params.employee_id).get()
            .then((querySnapshot)=> {
                querySnapshot.forEach(doc => {
                    this.employee_id=doc.data().employee_id
                    this.dept=doc.dept
                    this.position=doc.position
                    this.name=doc.name
                })
            })
        },
        deleteEmployee(){
            debugger
            db.collection('employees').where('employee_id','==',this.$route.params.employee_id).get()
            
            .then((querySnapshot)=>{
                querySnapshot.forEach(doc =>{doc.ref.delete();
                this.$router.push('/')}
                )
            })
        }
    } 
}
</script>



