<template>
    <div id="edit-employee">
        <h3>edit-employee</h3>
                <div class="row">
                    <form @submit.prevent="updateEmployee" class="col s12">
                    <div class="row">
                        <div class="input-field col s12">
                        <input type="text" v-model="employee_id" required>
                        </div>
                    </div>
                    <div class="row">
                        <div class="input-field col s12">
                        <input type="text" v-model="name" required>
                        </div>
                    </div>
                    <div class="row">
                        <div class="input-field col s12">
                        <input type="text" v-model="dept" required>
                        </div>
                    </div>
                    <div class="row">
                        <div class="input-field col s12">
                        <input type="text" v-model="position" required>
                        </div>
                    </div>
                    <button type="submit" class="btn">Submit</button>
                    <router-link to="/" class="btn grey">Cancel</router-link>
                    </form>
            </div>
     </div>
</template>

<script>
import db from './firebaseinit'
export default {
    name: 'edit-employee',
    data (){
        return{
            employee_id:null,
            name:null,
            dept:null,
            position:null,
        }
    },
    beforeRouteEnter(to,from,next){
        db.collection('employees').where('employee_id','==',to.params.employee_id).get()
        .then((querySnapshot)=>{querySnapshot.forEach(
            (doc)=>{next( vm=>{
                vm.employee_id=doc.data().employee_id,
                vm.dept=doc.data().dept,
                vm.position=doc.data().position,
                vm.name=doc.data().name
            }
            )}
        )})

    },
    watch:{
        '$router':'fetchData'
    },
    methods:{
        fetchData(){
             db.collection('employees').where('employee_id','==',$router.params.employee_id).get()
            .then((querySnapshot)=>{querySnapshot.forEach(
                (doc)=>{next( vm=>{
                    vm.employee_id=doc.data().employee_id,
                    vm.dept=doc.data().dept,
                    vm.position=doc.data().position,
                    vm.name=doc.data().name
                }
                )}
            )})
        },
       updateEmployee () {
        db.collection('employees').where('employee_id', '==', this.$route.params.employee_id).get().then((querySnapshot) => {
          querySnapshot.forEach((doc) => {
            doc.ref.update({
              employee_id: this.employee_id,
              name: this.name,
              dept: this.dept,
              position: this.position
            })
            .then(() => {
              this.$router.push({ name: 'viewEmployee', params: { employee_id: this.employee_id }})
            });
          })
        })
      }
    }
}
</script>



